3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	// Rounds up in MHPCO's favor, guarding against floating-point drift
25	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
26	const roundUpInFavor = (amount: number): number =>
27	  Math.ceil(Number(amount.toFixed(6)));
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE_PREMIUM = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	// A same-type group of exactly BLOCK_SIZE components forms one block priced at
37	// BLOCK_BASE_PREMIUM; any other count is priced per component. (Multi-block and
38	// block-plus-leftover pricing are not yet implemented.)
39	const componentGroupBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : count * COMPONENT_BASE_PREMIUM;
43	
44	const itemBasePremium = (item: Item): number =>
45	  isComponent(item) ? COMPONENT_BASE_PREMIUM : BASE_PREMIUMS[item.type];
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	const FIRST_INSURANCE_RATE = 0.1;
51	const LOYALTY_DISCOUNT_RATE = 0.2;
52	const LOYALTY_YEARS_THRESHOLD = 2;
53	const FOLLOWUP_DISCOUNT_RATE = 0.15;
54	
55	// A rate-based term contributes `rate * base` when its condition holds, else 0.
56	// Used for both surcharges (added) and discounts (subtracted).
57	const rateTermWhen = (applies: boolean, rate: number, base: number): number =>
58	  applies ? rate * base : 0;
59	
60	const itemSurcharge = (item: Item): number => {
61	  const base = itemBasePremium(item);
62	  const curse = rateTermWhen(item.cursed ?? false, CURSE_SURCHARGE_RATE, base);
63	  const highEnchantment = rateTermWhen(
64	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
65	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
66	    base,
67	  );
68	  return curse + highEnchantment;
69	};
70	
71	const countByType = (items: Item[]): Record<string, number> =>
72	  items.reduce<Record<string, number>>((counts, item) => {
73	    counts[item.type] = (counts[item.type] ?? 0) + 1;
74	    return counts;
75	  }, {});
76	
77	const sum = (values: number[]): number =>
78	  values.reduce((running, value) => running + value, 0);
79	
80	const basePremiumTotal = (items: Item[]): number => {
81	  const mainItems = items.filter((item) => !isComponent(item));
82	  const components = items.filter(isComponent);
83	
84	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
85	  const componentsTotal = sum(
86	    Object.values(countByType(components)).map(componentGroupBasePremium),
87	  );
88	
89	  return mainItemsTotal + componentsTotal;
90	};
91	
92	// Net policy-level adjustment derived from the policy base: the first-insurance
93	// surcharge (always) minus the loyalty discount (for established customers) and
94	// the follow-up discount (for contracts after the customer's first quote).
95	const policyBaseModifiers = (
96	  customer: Customer,
97	  policyBase: number,
98	  followUp: boolean,
99	): number => {
100	  const isLoyalCustomer = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
101	  const firstInsurance = rateTermWhen(true, FIRST_INSURANCE_RATE, policyBase);
102	  const loyaltyDiscount = rateTermWhen(isLoyalCustomer, LOYALTY_DISCOUNT_RATE, policyBase);
103	  const followUpDiscount = rateTermWhen(followUp, FOLLOWUP_DISCOUNT_RATE, policyBase);
104	  return firstInsurance - loyaltyDiscount - followUpDiscount;
105	};
106	
107	export interface QuoteOptions {
108	  followUp?: boolean;
109	}
110	
111	const isKnownType = (item: Item): boolean =>
112	  isComponent(item) || item.type in BASE_PREMIUMS;
113	
114	const assertKnownItemTypes = (items: Item[]): void => {
115	  const unknownItem = items.find((item) => !isKnownType(item));
116	  if (unknownItem) {
117	    throw new Error(`Unknown item type: ${unknownItem.type}`);
118	  }
119	};
120	
121	export const quote = (
122	  customer: Customer,
123	  items: Item[],
124	  options: QuoteOptions = {},
125	): QuoteResult => {
126	  assertKnownItemTypes(items);
127	  const policyBase = basePremiumTotal(items);
128	  const surcharges = sum(items.map(itemSurcharge));
129	  const exactPremium =
130	    policyBase +
131	    surcharges +
132	    policyBaseModifiers(customer, policyBase, options.followUp ?? false) +
133	    PROCESSING_FEE;
134	  return { premium: roundUpInFavor(exactPremium) };
135	};
