137	export interface Damage {
138	  itemType: string;
139	  amount: number;
140	}
141	
142	export interface Incident {
143	  cause: string;
144	  damages: Damage[];
145	}
146	
147	export interface ClaimResult {
148	  payout: number;
149	  remainingCap: number;
150	}
151	
152	const INSURANCE_VALUES: Record<string, number> = {
153	  sword: 1000,
154	  amulet: 600,
155	  staff: 800,
156	  potion: 400,
157	  rune: 250,
158	  moonstone: 250,
159	};
160	
161	const DEDUCTIBLE = 100;
162	const CAP_MULTIPLIER = 2;
163	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
164	const REDUCED_REIMBURSEMENT_RATE = 0.5;
165	
166	const insuranceSum = (items: Item[]): number =>
167	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
168	
169	// The reimbursement for a single damage event: the reimbursable amount less the
170	// per-event deductible. Items with enchantment >= 8 are reimbursed at 50 %.
171	// (The dragon-material clause and cap exhaustion are not yet applied.)
172	const damagePayout = (damage: Damage, item: Item): number => {
173	  const highlyEnchanted =
174	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
175	  const reimbursable = highlyEnchanted
176	    ? REDUCED_REIMBURSEMENT_RATE * damage.amount
177	    : damage.amount;
178	  return reimbursable - DEDUCTIBLE;
179	};
180	
181	export const claim = (items: Item[], incident: Incident): ClaimResult => {
182	  const cap = CAP_MULTIPLIER * insuranceSum(items);
183	  const payout = sum(
184	    incident.damages.map((damage) => {
185	      const item = items.find((candidate) => candidate.type === damage.itemType)!;
186	      return damagePayout(damage, item);
187	    }),
188	  );
189	  return { payout, remainingCap: cap - payout };
190	};
